<script>
import Header from "./components/Header";
import Home from "./views/Home";
import About from "./views/About";
import Skills from "./views/Skills";
import Projects from "./views/Projects";

export default {
  name: "App",
  components: { Header, Home, About, Skills, Projects },
  data: function() {
    return {
      scrollY: window.pageYOffset,
      views: new Array(),
      expandData: new Array(),
      visible: {
        home: false,
        skills: false,
        projects: false
      }
    };
  },
  methods: {
    buildBreakpoints: function() {
      const sections = document.querySelectorAll("section");

      sections.forEach((section, idx) => {
        const viewHeight = section.scrollHeight;
        const start = idx === 0 ? 0 : this.views[idx - 1].breakpoints.end;
        const end = viewHeight + start;

        let viewObject = {
          node: section,
          id: section.id,
          breakpoints: {
            start: start === 0 ? 0 : start - viewHeight / 3,
            quartile: start + viewHeight / 4,
            middle: start + viewHeight / 2,
            threeQuarter: start + viewHeight / 4 + 3,
            end: end
          }
        };

        this.views.push(viewObject);
      });
    },
    toggleExpand: function(object) {
      console.log(this.expandData[0] !== undefined);
      if (object === undefined || this.expandData[0] !== undefined) {
        this.expandData = new Array();
      } else {
        this.expandData.push(object);
      }
    },
    scrollListener: function() {
      this.scrollY = window.pageYOffset;

      this.views.forEach(view => {
        if (
          this.scrollY >= view.breakpoints.start &&
          this.scrollY <= view.breakpoints.end
        ) {
          this.visible[view.id] = true;
        } else {
          this.visible[view.id] = false;
        }
      });
    }
  },
  created: function() {
    this.$root.$on("expand", projectDetails =>
      this.toggleExpand(projectDetails)
    );
  },
  mounted: function() {
    this.buildBreakpoints();
    window.addEventListener("scroll", this.scrollListener);
    this.scrollListener();
  }
};
</script>

